import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import { Link, useLocation } from 'react-router-dom';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

// Fix react-leaflet default icon loading issue
let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34]
});

// Create a Crowded Icon (Red/Orange)
let CrowdedIcon = L.divIcon({
    className: 'custom-div-icon',
    html: `<div style="background-color: var(--brand-orange); width: 30px; height: 30px; border-radius: 50% 50% 50% 0; transform: rotate(-45deg); border: 2px solid white; box-shadow: 0 0 10px rgba(0,0,0,0.3); display: flex; align-items: center; justify-content: center;">
            <i class="fa-solid fa-fire" style="transform: rotate(45deg); color: white; font-size: 14px;"></i>
          </div>`,
    iconSize: [30, 30],
    iconAnchor: [15, 30],
    popupAnchor: [0, -30]
});

L.Marker.prototype.options.icon = DefaultIcon;

// Map controller to automatically pan/zoom map on data change
function MapController({ center, zoom }) {
  const map = useMap();
  useEffect(() => {
     if (center) {
         map.flyTo(center, zoom, {
             animate: true,
             duration: 1.5
         });
     }
  }, [center, zoom, map]);
  return null;
}

export default function ParkingMap() {
    const location = useLocation();
    const [parkingLots, setParkingLots] = useState([]);
    const [districts, setDistricts] = useState([]);
    const [selectedDistrict, setSelectedDistrict] = useState("");
    const [isLoading, setIsLoading] = useState(true);

    // Tamil Nadu default center
    const defaultCenter = [11.1271, 78.6569];
    const defaultZoom = 7;

    // Fallback coordinates for districts
    const districtCenterMap = {
        "Tiruchirappalli": [10.7905, 78.7047],
        "Chennai": [13.0827, 80.2707],
        "Madurai": [9.9252, 78.1198],
        "Coimbatore": [11.0168, 76.9558],
        "Salem": [11.6643, 78.1460],
        "Vellore": [12.9165, 79.1325],
        "Erode": [11.3410, 77.7172],
        "Thoothukudi": [8.8052, 78.1452],
        "Tirunelveli": [8.7139, 77.7567],
        "Kanchipuram": [12.8342, 79.7037],
        "Thanjavur": [10.7870, 79.1378],
        "Dindigul": [10.3673, 77.9803],
    };

    const [mapCenter, setMapCenter] = useState(defaultCenter);
    const [mapZoom, setMapZoom] = useState(defaultZoom);

    useEffect(() => {
        setIsLoading(true);
        // Fetch all parking lots
        axios.get("http://localhost:5000/parking")
             .then(res => {
                 setParkingLots(res.data);

                 // Extract valid unique districts dynamically
                 const uniqueDistricts = [...new Set(res.data.map(lot => lot.district).filter(Boolean))];
                 setDistricts(uniqueDistricts);

                 // Check for incoming state from ParkingList
                 if (location.state && location.state.selectedDistrict) {
                     const district = location.state.selectedDistrict;
                     setSelectedDistrict(district);

                     // Trigger initial zoom for incoming district
                     const districtLots = res.data.filter(l => l.district === district);
                     if (districtLots.length > 0) {
                        // Priority 1: Use specific lot avg if they have coords
                        // Priority 2: Use districtCenterMap
                        const lotsWithCoords = districtLots.filter(l => l.lat && l.lng);
                        if (lotsWithCoords.length > 0) {
                            const avgLat = lotsWithCoords.reduce((sum, l) => sum + l.lat, 0) / lotsWithCoords.length;
                            const avgLng = lotsWithCoords.reduce((sum, l) => sum + l.lng, 0) / lotsWithCoords.length;
                            setMapCenter([avgLat, avgLng]);
                        } else if (districtCenterMap[district]) {
                            setMapCenter(districtCenterMap[district]);
                        }
                        setMapZoom(12);
                     }
                 }
                 setIsLoading(false);
             })
             .catch(err => {
                 console.error("Error fetching parking lots:", err);
                 setIsLoading(false);
             });
    }, [location.state]);

    const handleDistrictChange = (e) => {
        const district = e.target.value;
        setSelectedDistrict(district);

        if (!district) {
            // Reset to Tamil Nadu
            setMapCenter(defaultCenter);
            setMapZoom(defaultZoom);
            return;
        }

        // Calculate center based on available parking lots in the district
        const districtLots = parkingLots.filter(l => l.district === district);

        if (districtLots.length > 0) {
            const lotsWithCoords = districtLots.filter(l => l.lat && l.lng);
            if (lotsWithCoords.length > 0) {
                const avgLat = lotsWithCoords.reduce((sum, l) => sum + l.lat, 0) / lotsWithCoords.length;
                const avgLng = lotsWithCoords.reduce((sum, l) => sum + l.lng, 0) / lotsWithCoords.length;
                setMapCenter([avgLat, avgLng]);
            } else if (districtCenterMap[district]) {
                setMapCenter(districtCenterMap[district]);
            }
            setMapZoom(12); // zoom in nicely into district
        } else if (districtCenterMap[district]) {
            // Even if no lots, zoom to the district and show empty state
            setMapCenter(districtCenterMap[district]);
            setMapZoom(12);
        }
    };

    // Filter lots
    const visibleLots = selectedDistrict 
        ? parkingLots.filter(l => l.district === selectedDistrict)
        : parkingLots;

    // Helper to check if a lot is crowded
    const isCrowded = (lot) => {
        if (!lot.totalSlots) return false;
        return (lot.bookedSlots / lot.totalSlots) >= 0.75;
    };

    return (
        <div className="dashboard-container" style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 100px)' }}>
            <div className="dashboard-header" style={{ marginBottom: '20px' }}>
                <div>
                    <h1 className="dashboard-title" style={{ fontSize: '1.8rem' }}>Parking Map</h1>
                    <p className="dashboard-subtitle">Explore smart parking across Tamil Nadu</p>
                </div>
            </div>

            <div className="card" style={{ flex: 1, display: 'flex', flexDirection: 'column', padding: '20px', backgroundColor: 'white', borderRadius: 'var(--radius-md)', boxShadow: 'var(--shadow-md)' }}>
                <div style={{ marginBottom: '20px', display: 'flex', gap: '15px', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
                        <select 
                            className="form-input" 
                            style={{ 
                                maxWidth: '300px', 
                                padding: '10px 15px', 
                                border: '2px solid #eef2f6', 
                                borderRadius: '12px',
                                fontSize: '0.95rem',
                                fontWeight: '600',
                                color: 'var(--text-primary)',
                                outline: 'none'
                            }}
                            value={selectedDistrict}
                            onChange={handleDistrictChange}
                        >
                            <option value="">All Tamil Nadu</option>
                            {districts.map(d => (
                                <option key={d} value={d}>{d}</option>
                            ))}
                        </select>
                    </div>

                    {/* Legend */}
                    <div style={{ display: 'flex', gap: '20px', fontSize: '0.85rem', fontWeight: '700' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <div style={{ width: '14px', height: '14px', background: '#2563eb', borderRadius: '4px' }}></div>
                            <span style={{ color: 'var(--text-secondary)' }}>Standard</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <div style={{ width: '14px', height: '14px', background: 'var(--brand-orange)', borderRadius: '4px' }}></div>
                            <span style={{ color: 'var(--text-secondary)' }}>High Demand</span>
                        </div>
                    </div>
                </div>

                <div style={{ flex: 1, borderRadius: 'var(--radius-sm)', overflow: 'hidden', border: '1px solid rgba(0,0,0,0.08)', position: 'relative' }}>

                    {/* Loading Indicator */}
                    {isLoading && (
                        <div style={{
                            position: 'absolute',
                            top: 0, left: 0, right: 0, bottom: 0,
                            background: 'rgba(255, 255, 255, 0.7)',
                            backdropFilter: 'blur(4px)',
                            zIndex: 1001,
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center'
                        }}>
                             <i className="fa-solid fa-circle-notch fa-spin" style={{ fontSize: '2.5rem', color: 'var(--accent-primary)', marginBottom: '15px' }}></i>
                             <p style={{ fontWeight: '700', color: 'var(--text-primary)' }}>Loading map data...</p>
                        </div>
                    )}

                    {/* Empty State Overlay - ONLY show if not loading AND a district is selected AND there are really no lots */}
                    {!isLoading && selectedDistrict && visibleLots.length === 0 && (
                        <div style={{
                            position: 'absolute',
                            top: 0, left: 0, right: 0, bottom: 0,
                            background: 'rgba(255, 255, 255, 0.85)',
                            backdropFilter: 'blur(4px)',
                            zIndex: 1000,
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            justifyContent: 'center',
                            textAlign: 'center',
                            padding: '20px'
                        }}>
                            <div style={{ background: 'var(--bg-primary)', width: '80px', height: '80px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '20px' }}>
                                <i className="fa-regular fa-map" style={{ fontSize: '2.5rem', color: 'var(--text-muted)' }}></i>
                            </div>
                            <h3 style={{ fontSize: '1.4rem', color: 'var(--text-primary)', marginBottom: '8px', fontWeight: '800' }}>Coming Soon to {selectedDistrict}</h3>
                            <p style={{ color: 'var(--text-secondary)', maxWidth: '300px', fontSize: '0.95rem' }}>We're currently setting up smart parking in this district. Check back soon!</p>
                            <button 
                                onClick={() => { setSelectedDistrict(""); setMapCenter(defaultCenter); setMapZoom(defaultZoom); }}
                                style={{ marginTop: '20px', padding: '10px 20px', background: 'var(--accent-primary)', color: 'white', border: 'none', borderRadius: '12px', fontWeight: '700', cursor: 'pointer' }}
                            >
                                View All Tamil Nadu
                            </button>
                        </div>
                    )}

                    <MapContainer center={defaultCenter} zoom={defaultZoom} style={{ height: '100%', width: '100%', zIndex: 0 }}>
                        <TileLayer
                            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                        />
                        <MapController center={mapCenter} zoom={mapZoom} />

                        {visibleLots.map(lot => {
                            // Use direct coords or fallback to district center
                            const position = (lot.lat && lot.lng) 
                                ? [lot.lat, lot.lng] 
                                : districtCenterMap[lot.district];

                            if (!position) return null;

                            return (
                                <Marker 
                                    key={lot._id} 
                                    position={position}
                                    icon={isCrowded(lot) ? CrowdedIcon : DefaultIcon}
                                >
                                    <Popup>
                                        <div style={{ padding: '8px', textAlign: 'center', minWidth: '180px' }}>
                                            {isCrowded(lot) && (
                                                <div style={{ color: 'var(--brand-orange)', fontWeight: '800', fontSize: '0.75rem', textTransform: 'uppercase', marginBottom: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '4px' }}>
                                                    <i className="fa-solid fa-fire"></i> High Demand
                                                </div>
                                            )}
                                            <h3 style={{ fontSize: '1.2rem', fontWeight: '800', marginBottom: '4px', color: 'var(--text-primary)', letterSpacing: '-0.02em' }}>{lot.name}</h3>
                                            <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', marginBottom: '12px', lineHeight: '1.4' }}>{lot.location}</p>

                                            <div style={{ background: 'var(--bg-primary)', padding: '12px', borderRadius: '14px', marginBottom: '16px' }}>
                                                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', marginBottom: '6px' }}>
                                                    <span style={{ color: 'var(--text-secondary)', fontWeight: '600' }}>Availability</span>
                                                    <span style={{ color: isCrowded(lot) ? 'var(--status-danger)' : 'var(--status-success)', fontWeight: '800' }}>
                                                        {lot.availableSlots} / {lot.totalSlots}
                                                    </span>
                                                </div>
                                                <div style={{ height: '8px', background: '#e2e8f0', borderRadius: '4px', overflow: 'hidden' }}>
                                                    <div style={{ 
                                                        height: '100%', 
                                                        width: `${(lot.availableSlots / lot.totalSlots) * 100}%`, 
                                                        background: isCrowded(lot) ? 'var(--status-danger)' : 'var(--status-success)',
                                                        transition: 'width 0.8s cubic-bezier(0.16, 1, 0.3, 1)'
                                                    }}></div>
                                                </div>
                                            </div>

                                            <Link 
                                                to={`/slots/${lot._id}`} 
                                                className="btn-primary" 
                                                style={{ display: 'inline-flex', padding: '12px 18px', fontSize: '0.9rem', borderRadius: 'var(--radius-sm)', textDecoration: 'none', color: 'white', background: 'var(--accent-primary)', fontWeight: '700' }}
                                            >
                                                View Slots <i className="fa-solid fa-arrow-right" style={{ marginLeft: '8px' }}></i>
                                            </Link>
                                        </div>
                                    </Popup>
                                </Marker>
                            );
                        })}
                    </MapContainer>
                </div>
            </div>
        </div>
    );
}
